type DbError struct {
	// Stringised version of the error. This is primarily to facilitate migration of older code.
	AsText   string
	Severity string
	Code     string
	Message  string
	Detail   witTypes.Option[string]
	// Any error information provided by Postgres and not captured above.
	Extras []witTypes.Tuple2[string, string]
}

const (
	// An error occurred but we do not have structured info for it
	QueryErrorText uint8 = 0
	// Postgres returned a structured database error
	QueryErrorDbError uint8 = 1
)

type QueryError struct {
	tag   uint8
	value any
}

func (self QueryError) Tag() uint8 {
	return self.tag
}

func (self QueryError) Text() string {
	if self.tag != QueryErrorText {
		panic("tag mismatch")
	}
	return self.value.(string)
}
func (self QueryError) DbError() DbError {
	if self.tag != QueryErrorDbError {
		panic("tag mismatch")
	}
	return self.value.(DbError)
}

func MakeQueryErrorText(value string) QueryError {
	return QueryError{QueryErrorText, value}
}
func MakeQueryErrorDbError(value DbError) QueryError {
	return QueryError{QueryErrorDbError, value}
}

const (
	ErrorConnectionFailed      uint8 = 0
	ErrorBadParameter          uint8 = 1
	ErrorQueryFailed           uint8 = 2
	ErrorValueConversionFailed uint8 = 3
	ErrorOther                 uint8 = 4
)

// Errors related to interacting with a database.
type Error struct {
	tag   uint8
	value any
}

func (self Error) Tag() uint8 {
	return self.tag
}

func (self Error) ConnectionFailed() string {
	if self.tag != ErrorConnectionFailed {
		panic("tag mismatch")
	}
	return self.value.(string)
}
func (self Error) BadParameter() string {
	if self.tag != ErrorBadParameter {
		panic("tag mismatch")
	}
	return self.value.(string)
}
func (self Error) QueryFailed() QueryError {
	if self.tag != ErrorQueryFailed {
		panic("tag mismatch")
	}
	return self.value.(QueryError)
}
func (self Error) ValueConversionFailed() string {
	if self.tag != ErrorValueConversionFailed {
		panic("tag mismatch")
	}
	return self.value.(string)
}
func (self Error) Other() string {
	if self.tag != ErrorOther {
		panic("tag mismatch")
	}
	return self.value.(string)
}

func MakeErrorConnectionFailed(value string) Error {
	return Error{ErrorConnectionFailed, value}
}
func MakeErrorBadParameter(value string) Error {
	return Error{ErrorBadParameter, value}
}
func MakeErrorQueryFailed(value QueryError) Error {
	return Error{ErrorQueryFailed, value}
}
func MakeErrorValueConversionFailed(value string) Error {
	return Error{ErrorValueConversionFailed, value}
}
func MakeErrorOther(value string) Error {
	return Error{ErrorOther, value}
}

